    embedding: DestinationMilvusEmbedding
    r"""Embedding configuration"""

    indexing: DestinationMilvusIndexing
    r"""Indexing configuration"""

    processing: DestinationMilvusProcessingConfigModel

    DESTINATION_TYPE: Annotated[
        Annotated[Milvus, AfterValidator(validate_const(Milvus.MILVUS))],
        pydantic.Field(alias="destinationType"),
    ] = Milvus.MILVUS

    omit_raw_text: Optional[bool] = False
    r"""Do not store the text that gets embedded along with the vector and the metadata in the destination. If set to true, only the vector and the metadata will be stored - in this case raw text for LLM use cases needs to be retrieved from another source."""

    @model_serializer(mode="wrap")
    def serialize_model(self, handler):
        optional_fields = set(["omit_raw_text"])
        serialized = handler(self)
        m = {}

        for n, f in type(self).model_fields.items():
            k = f.alias or n
            val = serialized.get(k, serialized.get(n))

            if val != UNSET_SENTINEL:
                if val is not None or k not in optional_fields:
                    m[k] = val

        return m


